        /* insertBmb02EtcCost */

	        INSERT
	          INTO BLGTIT( 
          		  COMPKEY, WAREKEY, BLHDCKY, BLHDCIT, BLRUNIT, DOCCATE, DOCTYPE
         		, BLITYPE, OWNERKY, PTNRKEY, BLRPMGB, BLRCSGB
         		, BLRCOST, BLRAMOT, BLRSUTX, BLRREMK
	          	, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER )
	        VALUES(
        		#{etc.compkey}, #{etc.warekey}, #{etc.blhdcky}, FN_BM_BLHDCIT(#{etc.compkey}, #{etc.warekey}, #{etc.blhdcky}), '-', '-', '-'
        		, 'SUM', #{etc.ownerky}, #{etc.ptnrkey}, #{etc.blrpmgb}, #{etc.blrcsgb}
        		, #{etc.blrcost}, #{etc.blramot}, 10, #{etc.blrremk}
	             , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
	             , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract} )

mapper.update:
/* updateBmb02Blrremk */

    UPDATE BLGTIT
       SET BLRREMK = #{etc.blrremk}
         , LMODATE = to_char(NOW() ,'YYYYMMDD')
         , LMOTIME = to_char(NOW() ,'hh24miss')
         , LMOUSER = #{userData.useract}
     WHERE COMPKEY = #{etc.compkey}
       AND WAREKEY = #{etc.warekey}
       AND BLHDCKY = #{etc.blhdcky}
       AND BLHDCIT = #{etc.blhdcit}
       AND BLITYPE = 'SUM'

mapper.select:
/* selectBmb02ItemList */
SELECT BI.COMPKEY, BI.WAREKEY, BI.BLHDCKY
     , BI.DOCCATE, BI.DOCTYPE, BI.OWNERKY, BI.PTNRKEY
     , BI.SKUMKEY, BI.SKUDESC
     , CASE WHEN BI.BLRUNIT = BI.SUOMKEY THEN IFNULL(SUM(BI.REFCQTY),0)
            WHEN BI.BLRUNIT != BI.SUOMKEY THEN IFNULL(CEILING(SUM(BI.REFCQTY) / PK.PACKQTY),0)
        ELSE 0 END AS REFCQTY
     , BI.BLRUNIT, BI.BLRPMGB, BI.BLRCSGB, BI.BLRTKGB
     , BI.BLRCOST
     , CASE WHEN BI.BLRUNIT = BI.SUOMKEY THEN IFNULL(SUM(BI.REFCQTY),0) * BI.BLRCOST
            WHEN BI.BLRUNIT != BI.SUOMKEY THEN IFNULL(CEILING(SUM(BI.REFCQTY) / PK.PACKQTY),0) * BI.BLRCOST
        ELSE 0 END AS BLRAMOT
  FROM BLGTHD BH
 INNER JOIN BLGTIT BI
    ON BH.COMPKEY = BI.COMPKEY
   AND BH.WAREKEY = BI.WAREKEY
   AND BH.BLHDCKY = BI.BLHDCKY
 INNER JOIN MSKUWC SK
    ON BI.COMPKEY = SK.COMPKEY
   AND BI.WAREKEY = SK.WAREKEY
   AND BI.OWNERKY = SK.OWNERKY
   AND BI.SKUMKEY = SK.SKUMKEY
   AND BI.BLRTKGB = SK.SKUGR01
  LEFT JOIN MPAKMA PK
    ON SK.COMPKEY = PK.COMPKEY
   AND SK.WAREKEY = PK.WAREKEY
   AND SK.PACKKEY = PK.PACKKEY
   AND PK.TRUNTYP = BI.BLRUNIT
 WHERE BH.COMPKEY = #{compkey}
   AND BH.WAREKEY = #{warekey}
   AND BH.BLHDCKY = #{blhdcky}
   AND BI.OWNERKY = #{ownerky}
   AND BI.PTNRKEY = #{ptnrkey}
   AND BI.BLRPMGB = #{blrpmgb}
   AND BI.BLRCSGB = #{blrcsgb}
   AND BI.BLRTKGB = #{blrtkgb}
   AND BI.BLRUNIT = #{blrunit}
   AND BI.DOCCATE = #{doccate}
   AND BI.DOCTYPE = #{doctype}
   AND BI.BLITYPE = 'ROW'
   AND BH.LCCNFYN = 'N'


   AND BI.BPLCODE = #{bplcode}


   AND BI.BVLCODE = #{bvlcode}


 GROUP BY BI.COMPKEY, BI.WAREKEY, BI.BLHDCKY, BI.DOCCATE, BI.DOCTYPE, BI.OWNERKY, BI.PTNRKEY
        , BI.SKUMKEY, BI.SKUDESC, BI.BLRUNIT, BI.BLRPMGB, BI.BLRCSGB, BI.BLRTKGB, BI.BLRCOST

/* sp_bm_confirm */
CALL sp_bm_confirm(
      #{compkey}
    , #{warekey}
    , #{blhdcky}
    , #{userData.useract}
    , #{omsgkey, mode=OUT, jdbcType=VARCHAR}
    , #{oresult, mode=OUT, jdbcType=INTEGER}
)

