/* insertBmb06EtcCost */

    INSERT
    INTO BTGTIT(COMPKEY, WAREKEY, BTHDCKY, BTHDCIT, BTITYPE, DOCCATE, DOCTYPE
              , PTNRKEY, BTRPMGB, BTRCSGB, VEHICKY, BTRUNIT, MDESTKY
              , BTRCOST, BTRAMOT, BTRSUTX, BTRREMK, REFCQTY
              , CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER )
    VALUES(
    #{etc.compkey}, #{etc.warekey}, #{etc.bthdcky}, FN_BM_BTHDCIT(#{etc.compkey}, #{etc.warekey}, #{etc.bthdcky}), 'SUM', '-', '-'
    , #{etc.ptnrkey}, #{etc.btrpmgb}, #{etc.btrcsgb}, #{etc.vehicky}, #{etc.btrunit}, #{etc.mdestky}
    , #{etc.btrcost}, #{etc.btramot}, 0, #{etc.btrremk}, #{etc.refcqty}
    , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
    , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract} )

