mapper.select:
/* selectBmb06ItemList */
SELECT BI.COMPKEY, BI.WAREKEY, BI.BTHDCKY, BI.BTHDCIT, BI.BTITYPE
     , BI.BFTCODE, BI.BVTCODE, BI.DOCCATE, BI.DOCTYPE, BI.MDESTKY
     , BI.VEHICKY, BI.PTNRKEY, FN_COM_TODATE(BI.POSTDAT) AS POSTDAT
     , BI.SKUMKEY, BI.SKUDESC
     , BI.REFCQTY, BI.BTRPMGB, BI.BTRCSGB, BI.BTRTKGB, BI.BTRUNIT
     , BI.BTRCOST, BI.BTRSUTX, BI.BTRTKNM, BI.SUOMKEY, BI.BTRAMOT
     , BI.VHPLNKY, BI.VHPLNIT
     , FN_COM_TODATE(BI.CREDATE) AS CREDATE, FN_COM_TOTIME(BI.CRETIME) AS CRETIME, fn_sy_usernam(BI.COMPKEY, BI.CREUSER) as CREUSER
  FROM BTGTHD BH
 INNER JOIN BTGTIT BI
    ON BH.COMPKEY = BI.COMPKEY
   AND BH.WAREKEY = BI.WAREKEY
   AND BH.BTHDCKY = BH.BTHDCKY
 WHERE BH.COMPKEY = #{compkey}
   AND BH.WAREKEY = #{warekey}
   AND BH.BTHDCKY = #{bthdcky}
   AND BI.PTNRKEY = #{ptnrkey}
   AND BI.BTRPMGB = #{btrpmgb}
   AND BI.BTRCSGB = #{btrcsgb}
   AND BI.BTRUNIT = #{btrunit}
   AND BI.DOCCATE = #{doccate}
   AND BI.DOCTYPE = #{doctype}
   AND BI.VEHICKY = #{vehicky}

   AND BI.BVTCODE = #{bvtcode}

   AND BI.BTITYPE = 'ROW'
   AND BH.TCCNFYN = 'N'

/* sp_bm_t_confirm */
CALL sp_bm_t_confirm(
    #{compkey}
    , #{warekey}
    , #{bthdcky}
    , #{userData.useract}
    , #{omsgkey, mode=OUT, jdbcType=VARCHAR}
    , #{oresult, mode=OUT, jdbcType=INTEGER}
    )

