/* insertBmb10Cost */
INSERT
  INTO BFTDTL (
			  COMPKEY, WAREKEY, BFTDTKY, BFTDTIT
			, PTNRKEY, VEHICKY, BTRDATE, BTMITCT
			, BTPRMCT, BTVATCT, BTENVCT, BTCARCT 
			, BTODUCT, BTDPSCT, BTCVICT, BTIAICT
			, CREDATE, CRETIME, CREUSER
			, LMODATE, LMOTIME, LMOUSER
			  )
VALUES
	( #{compkey} , #{warekey} , #{bftdtky} , fn_bm_bftdtit(#{compkey}, #{warekey}, #{bftdtky} )
	, #{ptnrkey} , #{vehicky} , REPLACE(#{btrdate},'-','') , #{btmitct}
	, #{btprmct} , #{btvatct} , #{btenvct} , #{btcarct}
	, #{btoduct} , #{btdpsct} , #{btcvict} , #{btiaict}
	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract} )

